mapper.select:
SELECT d.id_region, COUNT(DISTINCT d.id_device) AS cnt FROM c_ai_device d WHERE d.fg_active = '1' AND EXISTS ( SELECT 1 FROM c_ai_user_consultation_log ucl WHERE ucl.fg_active = '1' AND ucl.id_device = d.id_device
)
AND d.id_org = #{query.idOrg}
GROUP BY d.id_region

SELECT d.id_device AS idDevice, d.cd_device AS cdDevice, d.na_device AS naDevice, d.id_org AS idOrg, o.na_org AS naOrg, d.id_region AS idRegion, r.na_region AS naRegion, ( SELECT MAX(ucl5.na_doctor) FROM c_ai_user_consultation_log ucl5 WHERE ucl5.fg_active = '1' AND ucl5.id_device = d.id_device AND ucl5.consultation_time = ( SELECT MAX(ucl6.consultation_time) FROM c_ai_user_consultation_log ucl6 WHERE ucl6.fg_active = '1' AND ucl6.id_device = d.id_device ) ) AS naDoctor, ( SELECT MAX(ucl.consultation_time) FROM c_ai_user_consultation_log ucl WHERE ucl.fg_active = '1' AND ucl.id_device = d.id_device
) AS lastActiveTime, ( SELECT COUNT(1) FROM c_ai_user_consultation_log ucl WHERE ucl.fg_active = '1' AND ucl.id_device = d.id_device
) AS consultationCount, ( SELECT COUNT(1) FROM c_ai_user_consultation_log ucl WHERE ucl.fg_active = '1' AND ucl.id_device = d.id_device AND ucl.status = 'completed'
) AS effectiveConsultationCount FROM c_ai_device d LEFT JOIN c_ai_org o ON o.id_org = d.id_org AND o.fg_active = '1' LEFT JOIN c_ai_region r ON r.id_region = d.id_region AND r.fg_active = '1' WHERE d.fg_active = '1'
AND EXISTS ( SELECT 1 FROM c_ai_user_consultation_log ucl WHERE ucl.fg_active = '1' AND ucl.id_device = d.id_device
)
AND NOT EXISTS ( SELECT 1 FROM c_ai_user_consultation_log ucl WHERE ucl.fg_active = '1' AND ucl.id_device = d.id_device
)
ORDER BY CASE WHEN lastActiveTime IS NULL THEN 1 ELSE 0 END, lastActiveTime DESC
